import React, { useState } from "react";
import axios from 'axios';
import 'bootstrap/dist/css/bootstrap.css';
import './styles.css';

const Addition = () => {

  const [sum, setSum] = useState(0);
  const [nums, setNums] = useState({ num1: 0, num2: 0 });

  function updateNums(event) {
    setNums({ ...nums, [event.target.name]: Number(event.target.value) })

  }


  function add() {
    setSum(nums.num1 + nums.num2);

    axios.get('https://localhost:8998/add/{num1}/and/{num2}')
      .then((response) => {
        console.log(response.data);
        console.log(response.status);
        console.log(response.statusText);
      });


  }

  return (
    <div className="Addition" id="main">
      <link rel="icon" href="%PUBLIC_URL%/favicon.ico" />

      <nav class="navbar" style={{ backgroundColor: "#f2f2f2" }}
        id="navbar">

        <div class="container-fluid">
          <a class="navbar-brand" href="!#">
            <img src="https://getbootstrap.com/docs/5.2/assets/brand/bootstrap-logo-shadow.png" alt="Bootstrap Logo" width="30" height="24" class="d-inline-block align-text-top"></img>
            Peters Cool Website
          </a>
        </div>
      </nav>


      <div id="mypanel">
        <div id="image">
          <img id="headshot" src="headshot.png" alt="Headshot">
          </img>
        </div>

        <div id="mydetails">
          <textarea id="myname" name="myname" rows="1" cols="30">
            Peter Buonaiuto</textarea>
          <br />

          <textarea id="myinfo" name="myinfo" rows="4" cols="50">
            My name is Peter and I'm a Comp Sci masters student also completing my bachelors this semester. I like to program tools for construction because I'm into home construction as well as coding.
          </textarea>
        </div>
      </div>

      <div id="entry">
        <div>
          <span id="numberlabel" >First Number: </span>
          <div class="form-group" id="test">
            <input type="number" class="form-control" id="num1" placeholder="First Number" name="num1" value={nums.num1} onChange={updateNums} ></input>
          </div >
        </div>

        <br />

        <div>
          <span id="numberlabel" >Second Number: </span>
          <div class="form-group" id="test">
            <input type="number"
              class="form-control"
              id="num2"
              placeholder="Second Number"
              name = "num2"
              value = {nums.num2}
              onChange = {updateNums}>
            </input>
          </div>
        </div>
      </div>

      <br />
      <button type="button" class="btn btn-primary"
        style={{ margin: "10px" }} onClick={add}>Submit</button>

      <p style={{ padding: "10px" }}>Your Addition result from server = {sum}
        <br />
        Your Addition result from ReactJS = {sum}

      </p>


    </div>
  );
};

export default Addition;
